import { useRef, useState } from "react";
import ChartCard from "./ChartCard";
import KPICard from "./KPICard";
import InsightPanel from "./InsightPanel";
import VoicePanel from "./VoicePanel";

function loadH2C() {
  return new Promise((res, rej) => {
    if (window.html2canvas) { res(window.html2canvas); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
    s.onload = () => res(window.html2canvas);
    s.onerror = rej;
    document.head.appendChild(s);
  });
}

async function captureEl(el, scale = 2) {
  const h2c = await loadH2C();
  return h2c(el, {
    backgroundColor: "#0e0e12",
    scale,
    useCORS: true,
    allowTaint: true,
    logging: false,
    scrollX: 0,
    scrollY: 0,
    windowWidth: el.scrollWidth,
    windowHeight: el.scrollHeight,
  });
}

export default function DashboardScreen({ data, sessionId, colorSchema, onReset, sqlQueries }) {
  const { dashboard_title, charts, insights, summary, total_kpis_generated } = data;
  const exportRef  = useRef(null);
  const [exporting, setExporting]   = useState(false);
  const [exportType, setExportType] = useState("");
  const [showMenu, setShowMenu]     = useState(false);
  const [showSQL, setShowSQL]       = useState(false);
  const [activeTab, setActiveTab]   = useState("charts"); // "charts" | "kpis"

  const voiceCtx = charts.map(c => ({ kpi:c.kpi, chart_type:c.chart_type, data:c.data.slice(0,20) }));

  // ── PNG ──────────────────────────────────────────────────────────────────
  const exportPNG = async () => {
    setShowMenu(false); setExporting(true); setExportType("png");
    try {
      const canvas = await captureEl(exportRef.current);
      const a = document.createElement("a");
      a.download = `${dashboard_title.replace(/\s+/g,"_")}.png`;
      a.href = canvas.toDataURL("image/png", 1.0);
      a.click();
    } catch(e) { alert("PNG failed: " + e.message); }
    finally { setExporting(false); setExportType(""); }
  };

  // ── PDF — professional 3-page report ─────────────────────────────────────
  const exportPDF = async () => {
    setShowMenu(false); setExporting(true); setExportType("pdf");
    try {
      const canvas  = await captureEl(exportRef.current, 1.8);
      const imgData = canvas.toDataURL("image/png", 0.95);
      const date    = new Date().toLocaleDateString("en-US", { year:"numeric", month:"long", day:"numeric" });

      const insightCards = insights.map(ins => `
        <div class="ic">
          <div class="ic-kpi">${ins.kpi}</div>
          <div class="ic-row"><div class="ic-lbl">📊 What happened</div><div class="ic-txt">${ins.descriptive||""}</div></div>
          <div class="ic-row"><div class="ic-lbl">🔍 Why it happened</div><div class="ic-txt">${ins.diagnostic||""}</div></div>
          <div class="ic-row"><div class="ic-lbl">💡 What to do</div><div class="ic-txt">${ins.prescriptive||""}</div></div>
        </div>
      `).join("");

      const pw = window.open("", "_blank");
      if (!pw) { alert("Allow popups to export PDF."); setExporting(false); return; }

      pw.document.write(`<!DOCTYPE html><html><head>
<meta charset="utf-8"/>
<title>${dashboard_title} — Talking BI Report</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap');
  *{margin:0;padding:0;box-sizing:border-box;}
  body{font-family:'Inter',sans-serif;background:#fff;color:#1e293b;font-size:13px;}

  /* ── COVER ── */
  .cover{
    min-height:100vh;
    background:linear-gradient(160deg,#0e0e12 0%,#1a1208 40%,#0e0e12 100%);
    display:flex;flex-direction:column;
    padding:56px 64px;
    page-break-after:always;
    position:relative;overflow:hidden;
  }
  .cover::before{
    content:'';position:absolute;top:-200px;right:-200px;
    width:600px;height:600px;border-radius:50%;
    background:radial-gradient(circle,rgba(249,115,22,0.12),transparent 70%);
    pointer-events:none;
  }
  .c-brand{display:flex;align-items:center;gap:12px;margin-bottom:auto;}
  .c-icon{width:44px;height:44px;background:rgba(249,115,22,0.15);border:1px solid rgba(249,115,22,0.3);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:22px;}
  .c-name{font-size:20px;font-weight:800;color:#fff;}
  .c-name span{color:#f97316;}
  .c-center{flex:1;display:flex;flex-direction:column;justify-content:center;padding:60px 0 40px;}
  .c-eyebrow{font-size:10px;font-weight:700;color:#f97316;letter-spacing:0.18em;text-transform:uppercase;margin-bottom:18px;}
  .c-title{font-size:56px;font-weight:800;color:#fff;line-height:1.1;letter-spacing:-1.5px;margin-bottom:16px;}
  .c-sub{font-size:18px;color:rgba(255,255,255,0.45);font-weight:300;margin-bottom:48px;}
  .c-bar{width:56px;height:3px;background:linear-gradient(90deg,#f97316,#fb923c);border-radius:2px;margin-bottom:48px;}
  .c-stats{display:flex;gap:48px;}
  .c-stat-n{font-size:40px;font-weight:800;color:#f97316;letter-spacing:-1px;display:block;line-height:1;}
  .c-stat-l{font-size:11px;color:rgba(255,255,255,0.35);text-transform:uppercase;letter-spacing:0.1em;margin-top:6px;}
  .c-foot{padding-top:32px;border-top:1px solid rgba(255,255,255,0.07);display:flex;justify-content:space-between;}
  .c-foot p{font-size:11px;color:rgba(255,255,255,0.2);}

  /* ── DASHBOARD PAGE ── */
  .dp{background:#0e0e12;page-break-after:always;}
  .dp-hdr{background:#14141a;padding:20px 32px;border-bottom:1px solid #2a2a38;display:flex;justify-content:space-between;align-items:center;}
  .dp-hdr h2{font-size:16px;font-weight:700;color:#f0f0f8;}
  .dp-hdr p{font-size:11px;color:#9090b0;margin-top:2px;}
  .dp-badge{padding:4px 12px;background:rgba(249,115,22,0.1);border:1px solid rgba(249,115,22,0.2);border-radius:20px;color:#f97316;font-size:11px;font-weight:600;}
  .dp img{width:100%;display:block;}

  /* ── INSIGHTS PAGE ── */
  .ip{background:#fff;padding:56px 64px;page-break-before:always;}
  .ip-hdr{display:flex;justify-content:space-between;align-items:flex-start;padding-bottom:28px;border-bottom:2px solid #f1f5f9;margin-bottom:36px;}
  .ip-title{font-size:30px;font-weight:800;color:#1e293b;margin-bottom:6px;}
  .ip-sub{font-size:13px;color:#64748b;}
  .ip-meta{font-size:11px;color:#94a3b8;text-align:right;line-height:1.8;}
  .sum-box{background:linear-gradient(135deg,#f97316,#fb923c);border-radius:16px;padding:28px 32px;margin-bottom:36px;}
  .sum-box h3{font-size:10px;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:rgba(255,255,255,0.65);margin-bottom:12px;}
  .sum-box p{font-size:15px;color:#fff;line-height:1.8;}
  .sec-title{font-size:12px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:20px;padding-bottom:10px;border-bottom:1px solid #f1f5f9;}
  .ic{background:#f8fafc;border:1px solid #e2e8f0;border-left:3px solid #f97316;border-radius:12px;padding:20px 24px;margin-bottom:16px;}
  .ic-kpi{font-size:14px;font-weight:700;color:#f97316;margin-bottom:14px;padding-bottom:10px;border-bottom:1px solid #e2e8f0;}
  .ic-row{display:flex;gap:16px;margin-bottom:10px;}
  .ic-lbl{font-size:10px;font-weight:700;color:#94a3b8;width:130px;flex-shrink:0;text-transform:uppercase;letter-spacing:0.05em;padding-top:2px;}
  .ic-txt{font-size:13px;color:#334155;line-height:1.7;}
  .pdf-foot{position:fixed;bottom:0;left:0;right:0;height:34px;background:#f8fafc;border-top:1px solid #e2e8f0;display:flex;justify-content:space-between;align-items:center;padding:0 64px;font-size:10px;color:#94a3b8;}
  @media print{
    body{-webkit-print-color-adjust:exact;print-color-adjust:exact;}
    @page{margin:0;size:A4 portrait;}
    .pdf-foot{position:fixed;}
  }
</style></head><body>

<!-- Cover -->
<div class="cover">
  <div class="c-brand"><div class="c-icon">📊</div><div class="c-name">Talking <span>BI</span></div></div>
  <div class="c-center">
    <div class="c-eyebrow">Business Intelligence Report</div>
    <div class="c-title">${dashboard_title}</div>
    <div class="c-sub">AI-Generated Analytics Report</div>
    <div class="c-bar"></div>
    <div class="c-stats">
      <div><span class="c-stat-n">${total_kpis_generated}</span><div class="c-stat-l">Charts Generated</div></div>
      <div><span class="c-stat-n">${insights.length}</span><div class="c-stat-l">KPIs Analyzed</div></div>
      <div><span class="c-stat-n">6</span><div class="c-stat-l">Insight Types</div></div>
    </div>
  </div>
  <div class="c-foot"><p>Confidential · Generated by Talking BI</p><p>${date}</p></div>
</div>

<!-- Dashboard image -->
<div class="dp">
  <div class="dp-hdr">
    <div><h2>${dashboard_title}</h2><p>Dashboard Overview · ${date}</p></div>
    <div class="dp-badge">${total_kpis_generated} Visualizations</div>
  </div>
  <img src="${imgData}"/>
</div>

<!-- Insights -->
<div class="ip">
  <div class="ip-hdr">
    <div><div class="ip-title">AI Insights & Analysis</div><div class="ip-sub">Automatically generated insights from your dashboard data</div></div>
    <div class="ip-meta">Talking BI<br/>${date}</div>
  </div>
  ${summary?`<div class="sum-box"><h3>⚡ Executive Summary</h3><p>${summary}</p></div>`:""}
  <div class="sec-title">📊 Chart-by-Chart Insights</div>
  ${insightCards}
</div>

<div class="pdf-foot"><span>Talking BI · AI-Powered Business Intelligence</span><span>${dashboard_title} · ${date}</span></div>
<script>window.onload=function(){setTimeout(function(){window.print();},700);};<\/script>
</body></html>`);
      pw.document.close();
    } catch(e) { alert("PDF failed: "+e.message); }
    finally { setExporting(false); setExportType(""); }
  };

  return (
    <div style={S.screen}>
      {/* ── Topbar ──────────────────────────────────────────────────────── */}
      <div style={S.topbar}>
        <div style={S.topLeft}>
          <div style={S.logoWrap}>
            <svg width="16" height="16" viewBox="0 0 32 32" fill="none">
              <path d="M8 22L13 10l5 7 4-9" stroke="#f97316" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="22" cy="9" r="2.5" fill="#fb923c"/>
            </svg>
          </div>
          <h1 style={S.title}>{dashboard_title}</h1>
          <div style={S.badge}>{total_kpis_generated} charts</div>
        </div>

        <div style={S.actions}>
          {/* SQL button */}
          {sqlQueries?.length > 0 && (
            <button style={S.sqlBtn} onClick={()=>setShowSQL(v=>!v)} title="View SQL queries">
              <svg width="13" height="13" viewBox="0 0 13 13" fill="none">
                <rect x=".5" y=".5" width="12" height="12" rx="2" stroke="currentColor" strokeWidth="1.1"/>
                <path d="M3 4l2 2-2 2M7 8h3" stroke="currentColor" strokeWidth="1.1" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
              SQL
            </button>
          )}

          {/* Export */}
          <div style={{ position:"relative" }}>
            <button style={{ ...S.exportBtn, ...(exporting?S.off:{}) }} onClick={()=>!exporting&&setShowMenu(v=>!v)} disabled={exporting}>
              {exporting?<><span style={S.spin}/>{exportType==="pdf"?"Saving PDF…":"Saving PNG…"}</>:<>↓ Export <span style={{ fontSize:9 }}>▼</span></>}
            </button>
            {showMenu && (
              <div style={S.menu}>
                <button style={S.mItem} onClick={exportPNG}><div style={S.mIcon}>🖼️</div><div><div style={S.mT}>Save as PNG</div><div style={S.mS}>High-res image (2×)</div></div></button>
                <div style={S.mSep}/>
                <button style={S.mItem} onClick={exportPDF}><div style={S.mIcon}>📄</div><div><div style={{ ...S.mT, color:"#f59e0b" }}>Save as PDF</div><div style={S.mS}>Professional 3-page report</div></div></button>
              </div>
            )}
          </div>
          <button style={S.newBtn} onClick={onReset}>↺ New</button>
        </div>
      </div>

      {/* SQL Modal */}
      {showSQL && sqlQueries?.length > 0 && (
        <div style={S.sqlModal}>
          <div style={S.sqlModalHdr}>
            <span style={S.sqlModalTitle}>SQL Queries Generated by AI</span>
            <button style={S.sqlClose} onClick={()=>setShowSQL(false)}>✕</button>
          </div>
          <div style={S.sqlModalBody}>
            {sqlQueries.map((q,i)=>(
              <div key={i} style={S.sqlCard}>
                <div style={S.sqlKpi}>{i+1}. {q.kpi}</div>
                <pre style={S.sqlCode}>{q.sql}</pre>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Body ────────────────────────────────────────────────────────── */}
      <div style={S.body}>
        <div style={S.main}>
          {/* Tabs */}
          <div style={S.tabs}>
            <button style={{ ...S.tab, ...(activeTab==="kpis"?S.tabOn:{}) }} onClick={()=>setActiveTab("kpis")}>
              📊 KPI Cards
            </button>
            <button style={{ ...S.tab, ...(activeTab==="charts"?S.tabOn:{}) }} onClick={()=>setActiveTab("charts")}>
              📈 Charts
            </button>
            <button style={{ ...S.tab, ...(activeTab==="both"?S.tabOn:{}) }} onClick={()=>setActiveTab("both")}>
              ⚡ Both
            </button>
          </div>

          <div ref={exportRef} style={S.exportArea}>
            {/* KPI Cards */}
            {(activeTab==="kpis"||activeTab==="both") && (
              <div style={S.kpiGrid}>
                {charts.map((chart,i) => (
                  <KPICard key={chart.kpi} chart={chart} colorSchema={colorSchema} index={i} />
                ))}
              </div>
            )}

            {/* Charts */}
            {(activeTab==="charts"||activeTab==="both") && (
              <div style={S.chartGrid}>
                {charts.map((chart,i) => (
                  <ChartCard key={chart.kpi} chart={chart} colorSchema={colorSchema} index={i} />
                ))}
              </div>
            )}
          </div>
        </div>

        <div style={S.sidebar}>
          <VoicePanel sessionId={sessionId} dashboardContext={voiceCtx} />
          <InsightPanel insights={insights} summary={summary} />
        </div>
      </div>

      {showMenu && <div style={S.overlay} onClick={()=>setShowMenu(false)}/>}
    </div>
  );
}

